import React, { useState } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import { evaluateAnswer, finalizeSession } from "../api";

const verdictConfig = {
  Excellent: { color: "var(--green)", bg: "var(--green-dim)", icon: "🏆" },
  Good: { color: "var(--green)", bg: "var(--green-dim)", icon: "✅" },
  Average: { color: "var(--yellow)", bg: "var(--yellow-dim)", icon: "📊" },
  "Needs Improvement": { color: "var(--yellow)", bg: "var(--yellow-dim)", icon: "📝" },
  Poor: { color: "var(--red)", bg: "var(--red-dim)", icon: "⚠️" },
};

export default function Interview() {
  const location = useLocation();
  const navigate = useNavigate();
  const { sessionId, questions, role } = location.state || {};

  const [current, setCurrent] = useState(0);
  const [answer, setAnswer] = useState("");
  const [feedback, setFeedback] = useState(null);
  const [allFeedback, setAllFeedback] = useState([]);
  const [evaluating, setEvaluating] = useState(false);
  const [error, setError] = useState("");
  const [finishing, setFinishing] = useState(false);

  if (!questions || !sessionId) {
    return (
      <div style={{ textAlign: "center", padding: "80px 24px" }}>
        <p style={{ color: "var(--text2)" }}>No interview session found.</p>
        <button className="btn btn-primary" onClick={() => navigate("/")} style={{ marginTop: "16px" }}>
          ← Go Home
        </button>
      </div>
    );
  }

  const progress = ((current) / questions.length) * 100;
  const currentQ = questions[current];

  // Support both MCQ objects and plain strings (fallback)
  const isMCQ = currentQ && typeof currentQ === "object" && currentQ.options;
  const questionText = isMCQ ? currentQ.question : currentQ;
  const options = isMCQ ? currentQ.options : [];

  const handleEvaluate = async () => {
    if (!answer.trim()) return;
    setEvaluating(true);
    setError("");
    try {
      const res = await evaluateAnswer(sessionId, current + 1, questionText, answer, role);
      const fb = res.data.feedback;
      setFeedback(fb);
      setAllFeedback((prev) => [...prev, { question: questionText, answer, feedback: fb }]);
    } catch {
      setError("Failed to evaluate. Please try again.");
    } finally {
      setEvaluating(false);
    }
  };

  const handleNext = async () => {
    if (current + 1 >= questions.length) {
      setFinishing(true);
      try {
        await finalizeSession(sessionId);
        navigate(`/results/${sessionId}`, { state: { allFeedback: [...allFeedback], role } });
      } catch {
        setError("Failed to finalize session.");
        setFinishing(false);
      }
    } else {
      setCurrent((p) => p + 1);
      setAnswer("");
      setFeedback(null);
    }
  };

  const vc = feedback ? (verdictConfig[feedback.verdict] || verdictConfig["Average"]) : null;

  return (
    <div style={{ maxWidth: "780px", margin: "0 auto", padding: "40px 24px" }}>
      {/* Header */}
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: "32px" }}>
        <div>
          <span className="tag tag-accent">{role}</span>
        </div>
        <div style={{ color: "var(--text2)", fontSize: "14px", fontFamily: "Syne, sans-serif", fontWeight: 600 }}>
          Question {current + 1} of {questions.length}
        </div>
      </div>

      {/* Progress Bar */}
      <div style={{ height: "4px", background: "var(--surface3)", borderRadius: "2px", marginBottom: "40px", overflow: "hidden" }}>
        <div style={{
          height: "100%",
          width: `${progress}%`,
          background: "linear-gradient(90deg, var(--accent), var(--accent2))",
          borderRadius: "2px",
          transition: "width 0.5s ease",
        }} />
      </div>

      {/* Question Card */}
      <div className="card" style={{ marginBottom: "24px", borderColor: "var(--border2)" }}>
        <div style={{ color: "var(--text3)", fontSize: "12px", fontFamily: "Syne, sans-serif", fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.08em", marginBottom: "14px" }}>
          Q{current + 1}
        </div>
        <p style={{ fontSize: "19px", fontWeight: 500, lineHeight: 1.55, color: "var(--text)" }}>
          {questionText}
        </p>
      </div>

      {/* MCQ Options */}
      {!feedback && isMCQ && (
        <>
          <div style={{ display: "flex", flexDirection: "column", gap: "12px", marginBottom: "20px" }}>
            {options.map((option, idx) => {
              const isSelected = answer === option;
              return (
                <label
                  key={idx}
                  style={{
                    display: "flex",
                    alignItems: "center",
                    gap: "14px",
                    padding: "14px 18px",
                    border: `2px solid ${isSelected ? "var(--accent)" : "var(--border)"}`,
                    borderRadius: "var(--radius-sm)",
                    background: isSelected ? "var(--accent-dim, rgba(124,106,247,0.08))" : "var(--surface2)",
                    cursor: evaluating ? "not-allowed" : "pointer",
                    transition: "border-color 0.2s, background 0.2s",
                    opacity: evaluating ? 0.6 : 1,
                  }}
                >
                  <input
                    type="radio"
                    name={`mcq-${current}`}
                    value={option}
                    checked={isSelected}
                    onChange={() => !evaluating && setAnswer(option)}
                    disabled={evaluating}
                    style={{
                      width: "18px",
                      height: "18px",
                      accentColor: "var(--accent)",
                      cursor: evaluating ? "not-allowed" : "pointer",
                      flexShrink: 0,
                    }}
                  />
                  <span style={{ fontSize: "15px", color: "var(--text)", lineHeight: 1.5 }}>
                    {option}
                  </span>
                </label>
              );
            })}
          </div>

          {error && (
            <div style={{ padding: "12px 16px", background: "var(--red-dim)", border: "1px solid rgba(240,98,106,0.3)", borderRadius: "var(--radius-sm)", color: "var(--red)", marginBottom: "16px" }}>
              {error}
            </div>
          )}

          <button
            className="btn btn-primary"
            onClick={handleEvaluate}
            disabled={!answer.trim() || evaluating}
            style={{ width: "100%", justifyContent: "center", padding: "15px" }}
          >
            {evaluating ? (
              <><span style={{ animation: "spin 1s linear infinite", display: "inline-block" }}>⟳</span> Evaluating your answer…</>
            ) : "Submit Answer →"}
          </button>
        </>
      )}

      {/* Fallback: textarea for non-MCQ questions */}
      {!feedback && !isMCQ && (
        <>
          <textarea
            rows={7}
            placeholder="Type your answer here… Be specific, use examples from your experience, and explain your reasoning."
            value={answer}
            onChange={(e) => setAnswer(e.target.value)}
            style={{ marginBottom: "16px" }}
            disabled={evaluating}
          />
          {error && (
            <div style={{ padding: "12px 16px", background: "var(--red-dim)", border: "1px solid rgba(240,98,106,0.3)", borderRadius: "var(--radius-sm)", color: "var(--red)", marginBottom: "16px" }}>
              {error}
            </div>
          )}
          <button
            className="btn btn-primary"
            onClick={handleEvaluate}
            disabled={!answer.trim() || evaluating}
            style={{ width: "100%", justifyContent: "center", padding: "15px" }}
          >
            {evaluating ? (
              <><span style={{ animation: "spin 1s linear infinite", display: "inline-block" }}>⟳</span> Evaluating your answer…</>
            ) : "Submit Answer →"}
          </button>
        </>
      )}

      {/* Feedback Panel */}
      {feedback && vc && (
        <div style={{ animation: "fadeUp 0.4s ease" }}>
          {/* Verdict + Score */}
          <div style={{
            display: "flex",
            alignItems: "center",
            gap: "16px",
            padding: "20px 24px",
            background: vc.bg,
            border: `1px solid ${vc.color}40`,
            borderRadius: "var(--radius)",
            marginBottom: "20px",
          }}>
            <div style={{ fontSize: "36px" }}>{vc.icon}</div>
            <div style={{ flex: 1 }}>
              <div style={{ fontFamily: "Syne, sans-serif", fontWeight: 800, fontSize: "22px", color: vc.color }}>
                {feedback.verdict}
              </div>
              <div style={{ color: "var(--text2)", fontSize: "14px" }}>Your score for this answer</div>
            </div>
            <div style={{
              fontFamily: "Syne, sans-serif",
              fontWeight: 800,
              fontSize: "42px",
              color: vc.color,
              minWidth: "80px",
              textAlign: "right",
            }}>
              {feedback.score}<span style={{ fontSize: "18px", color: "var(--text3)" }}>/10</span>
            </div>
          </div>

          {/* Feedback Grid */}
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "16px", marginBottom: "20px" }}>
            <div className="card" style={{ borderColor: "rgba(61,214,140,0.2)" }}>
              <div style={{ color: "var(--green)", fontFamily: "Syne, sans-serif", fontWeight: 700, fontSize: "12px", textTransform: "uppercase", letterSpacing: "0.06em", marginBottom: "10px" }}>
                ✓ Strengths
              </div>
              <p style={{ color: "var(--text2)", fontSize: "14px", lineHeight: 1.6 }}>{feedback.strengths}</p>
            </div>
            <div className="card" style={{ borderColor: "rgba(240,98,106,0.2)" }}>
              <div style={{ color: "var(--red)", fontFamily: "Syne, sans-serif", fontWeight: 700, fontSize: "12px", textTransform: "uppercase", letterSpacing: "0.06em", marginBottom: "10px" }}>
                ✗ Weaknesses
              </div>
              <p style={{ color: "var(--text2)", fontSize: "14px", lineHeight: 1.6 }}>{feedback.weaknesses}</p>
            </div>
          </div>

          <div className="card" style={{ marginBottom: "16px", borderColor: "rgba(124,106,247,0.2)" }}>
            <div style={{ color: "var(--accent2)", fontFamily: "Syne, sans-serif", fontWeight: 700, fontSize: "12px", textTransform: "uppercase", letterSpacing: "0.06em", marginBottom: "10px" }}>
              💡 Ideal Answer
            </div>
            <p style={{ color: "var(--text2)", fontSize: "14px", lineHeight: 1.6 }}>{feedback.ideal_answer}</p>
          </div>

          <div style={{
            display: "flex",
            alignItems: "flex-start",
            gap: "12px",
            padding: "16px 18px",
            background: "var(--yellow-dim)",
            border: "1px solid rgba(245,197,66,0.3)",
            borderRadius: "var(--radius-sm)",
            marginBottom: "24px",
          }}>
            <span style={{ fontSize: "18px" }}>🎯</span>
            <div>
              <div style={{ color: "var(--yellow)", fontFamily: "Syne, sans-serif", fontWeight: 700, fontSize: "12px", textTransform: "uppercase", letterSpacing: "0.06em", marginBottom: "6px" }}>
                Pro Tip
              </div>
              <p style={{ color: "var(--text2)", fontSize: "14px", lineHeight: 1.5 }}>{feedback.tip}</p>
            </div>
          </div>

          <button
            className="btn btn-primary"
            onClick={handleNext}
            disabled={finishing}
            style={{ width: "100%", justifyContent: "center", padding: "15px" }}
          >
            {finishing ? (
              <><span style={{ animation: "spin 1s linear infinite", display: "inline-block" }}>⟳</span> Saving results…</>
            ) : current + 1 >= questions.length ? "View Final Results 🏁" : `Next Question →`}
          </button>
        </div>
      )}

      <style>{`
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        @keyframes fadeUp { from { opacity: 0; transform: translateY(12px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
}
